import { createMiddleware, tool } from 'langchain';
import { z } from 'zod';
import * as fs from 'fs';
import * as path from 'path';
import { ToolMessage } from '@langchain/core/messages';

const PROJECT_ROOT = process.cwd();

/**
 * 安全校验：限制文件访问范围，防止越权访问
 */
function resolveSafePath(relativePath: string): string {
  const resolved = path.resolve(PROJECT_ROOT, relativePath);
  if (!resolved.startsWith(PROJECT_ROOT)) {
    throw new Error(`路径越权访问: ${relativePath}`);
  }
  return resolved;
}

// ---- 6 个文件系统工具 ----

const lsTool = tool(
  async ({ dirPath }: { dirPath: string }) => {
    const target = resolveSafePath(dirPath || '.');
    if (!fs.existsSync(target)) {
      return `目录不存在: ${dirPath}`;
    }
    const stats = fs.statSync(target);
    if (!stats.isDirectory()) {
      return `路径不是目录: ${dirPath}`;
    }
    const entries = fs.readdirSync(target, { withFileTypes: true });
    const result = entries.map(e => {
      const prefix = e.isDirectory() ? '[DIR]' : '[FILE]';
      return `${prefix} ${e.name}`;
    }).join('\n');
    return result || '(空目录)';
  },
  {
    name: 'ls',
    description: '列出指定目录下的文件和子目录',
    schema: z.object({
      dirPath: z.string().optional().default('.').describe('目录路径，默认为当前目录'),
    }),
  }
);

const readFileTool = tool(
  async ({ filePath }: { filePath: string }) => {
    const target = resolveSafePath(filePath);
    if (!fs.existsSync(target)) {
      return `文件不存在: ${filePath}`;
    }
    const stats = fs.statSync(target);
    if (stats.isDirectory()) {
      return `路径是目录，不是文件: ${filePath}`;
    }
    const content = fs.readFileSync(target, 'utf-8');
    return content;
  },
  {
    name: 'read_file',
    description: '读取指定文件的全部内容',
    schema: z.object({
      filePath: z.string().describe('文件路径'),
    }),
  }
);

const writeFileTool = tool(
  async ({ filePath, content }: { filePath: string; content: string }) => {
    const target = resolveSafePath(filePath);
    const dir = path.dirname(target);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
    fs.writeFileSync(target, content, 'utf-8');
    return `文件已写入: ${filePath} (${content.length} 字节)`;
  },
  {
    name: 'write_file',
    description: '将内容写入指定路径的文件，自动创建不存在的父目录',
    schema: z.object({
      filePath: z.string().describe('文件路径'),
      content: z.string().describe('文件内容'),
    }),
  }
);

const editFileTool = tool(
  async ({ filePath, oldString, newString }: { filePath: string; oldString: string; newString: string }) => {
    const target = resolveSafePath(filePath);
    if (!fs.existsSync(target)) {
      return `文件不存在: ${filePath}`;
    }
    const content = fs.readFileSync(target, 'utf-8');
    if (!content.includes(oldString)) {
      return `未找到匹配的内容，无法替换`;
    }
    const updated = content.replaceAll(oldString, newString);
    fs.writeFileSync(target, updated, 'utf-8');
    return `文件已编辑: ${filePath}`;
  },
  {
    name: 'edit_file',
    description: '替换文件中指定的旧字符串为新字符串，支持全局替换',
    schema: z.object({
      filePath: z.string().describe('文件路径'),
      oldString: z.string().describe('要替换的原始内容'),
      newString: z.string().describe('替换后的新内容'),
    }),
  }
);

const globTool = tool(
  async ({ pattern }: { pattern: string }) => {
    // 简易 glob 实现（递归匹配 ** 通配符）
    function walk(dir: string, pat: string, base: string, results: string[]): void {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const e of entries) {
        const full = path.join(dir, e.name);
        const relative = path.relative(base, full);
        if (e.isDirectory()) {
          walk(full, pat, base, results);
        } else {
          // 简易匹配：支持 * 和 ** 通配符
          const regex = new RegExp(
            '^' + pat.replace(/\*\*/g, '.*').replace(/\*/g, '[^/\\\\]*') + '$'
          );
          if (regex.test(relative) || regex.test(e.name)) {
            results.push(relative);
          }
        }
      }
    }
    const results: string[] = [];
    walk(PROJECT_ROOT, pattern, PROJECT_ROOT, results);
    return results.length > 0 ? results.join('\n') : '(无匹配结果)';
  },
  {
    name: 'glob',
    description: '按通配符模式搜索文件，支持 ** 和 * 通配符',
    schema: z.object({
      pattern: z.string().describe('glob 模式，例如 "**/*.ts" 匹配所有 TypeScript 文件'),
    }),
  }
);

const grepTool = tool(
  async ({ pattern, filePath }: { pattern: string; filePath?: string }) => {
    const searchDir = filePath ? resolveSafePath(filePath) : PROJECT_ROOT;
    const isDir = fs.existsSync(searchDir) && fs.statSync(searchDir).isDirectory();
    const results: string[] = [];
    const regex = new RegExp(pattern);

    function walk(dir: string) {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const e of entries) {
        const full = path.join(dir, e.name);
        if (e.isDirectory()) {
          // 跳过 node_modules 和 .git
          if (e.name === 'node_modules' || e.name === '.git') continue;
          walk(full);
        } else if (e.isFile()) {
          try {
            const content = fs.readFileSync(full, 'utf-8');
            const lines = content.split('\n');
            lines.forEach((line, idx) => {
              if (regex.test(line)) {
                const rel = path.relative(PROJECT_ROOT, full);
                results.push(`${rel}:${idx + 1}: ${line.trim()}`);
              }
            });
          } catch {
            // 忽略无法读取的文件（二进制等）
          }
        }
      }
    }

    if (isDir) {
      walk(searchDir);
    } else if (fs.existsSync(searchDir) && fs.statSync(searchDir).isFile()) {
      const content = fs.readFileSync(searchDir, 'utf-8');
      content.split('\n').forEach((line, idx) => {
        if (regex.test(line)) {
          results.push(`${path.relative(PROJECT_ROOT, searchDir)}:${idx + 1}: ${line.trim()}`);
        }
      });
    }

    return results.length > 0 ? results.join('\n') : '(无匹配结果)';
  },
  {
    name: 'grep',
    description: '在文件或目录中搜索匹配正则表达式的行',
    schema: z.object({
      pattern: z.string().describe('正则表达式搜索模式'),
      filePath: z.string().optional().describe('搜索范围：文件路径或目录路径，不传则搜索整个项目'),
    }),
  }
);

// ---- 中间件导出 ----

export const fileSystemMiddleware = createMiddleware({
  name: 'fileSystemMiddleware',
  tools: [lsTool, readFileTool, writeFileTool, editFileTool, globTool, grepTool],
});

