import 'dotenv/config';
import React, { useState } from 'react';
import { render, Text, Box, useInput, useApp } from 'ink';
import TextInput from 'ink-text-input';
import { ChatView, ChatMessage } from './chat.tsx'
import { initChatModel } from 'langchain';
import { getAgent } from '../agent/agent.ts';

const QWEN_LOGO = `
 ██╗   ██╗ ██████╗ ██╗   ██╗
 ██╗ ██╔╝██╔═══██╗██║   ██║
  ╚████╔╝ ██║   ██║██║   ██║
   ╚██╔╝  ██║   ██║██║   ██║
    ██║   ╚██████╔╝╚██████╔
    ╚═╝    ╚═════╝  ╚═════╝
`;

export function App() {
  const [value, setValue] = useState('');
  const { exit } = useApp();
  // 流式请求数据
  let fullText = ""
  const [streamingText, setStreamingText] = useState("");
  // 历史数据
  const [messages, setMessages] = useState<ChatMessage[]>([]);

  // 退出
  useInput((_input, key) => {
    if (key.escape) {
      exit();
    }
  });

  const handleSubmit = async (text: string) => {
    try {
      if (value.trim()) {
        setValue('');
      }

      // 获取主agent
      const agent = await getAgent();


      // 拼接信息
      setMessages((prev) => [...prev, { role: "user", content: text }]);

      const response = await agent.stream({
        messages: [{ role: "user", content: text }],
      },{
        streamMode: 'messages',
        configurable: { thread_id: "default-thread" },
      });

      // 流式请求处理
      for await (const chunk of response) {
        const [messageChunk, metadata] = chunk
        if(messageChunk.content){

        }
        fullText += messageChunk.content
        setStreamingText(fullText);
      }

      setStreamingText("");
      setMessages((prev) => [...prev, { role: "assistant", content: fullText }]);

    } catch (error) {
      console.error("在handleSubmit中捕获到:", error)
    }

  }


  return (
    <Box flexDirection="column" width="100%">
      {/* Logo + 右侧内容区 左右布局 */}
      <Box width="100%">
        {/* QWEN ASCII Logo */}
        <Box width={36}>
          <Text color="cyan">{QWEN_LOGO}</Text>
        </Box>

        {/* 右侧内容区 */}
        <Box flexGrow={1} flexDirection="column" borderStyle="single" borderColor="gray" paddingX={1}>
          {/* Header */}
          <Box flexDirection="column" justifyContent="center">
            <Text bold color="magenta">{'>_ Qwen Code'}</Text>
            <Text color="gray"> (v0.19.2)</Text>
          </Box>

          {/* Info Lines */}
          <Box flexDirection="column" marginTop={1} paddingLeft={1}>
            <Text>Token Plan | [ModelStudio Token Plan] qwen3.7-max</Text>
            <Text color="gray">F:\agent\aiAgent\code</Text>
          </Box>
        </Box>
      </Box>


      {/* Hint */}
      <Box marginTop={1} paddingLeft={1}>
        <Text color="gray">提示： 试试 </Text>
        <Text color="cyan">/insight</Text>
        <Text color="gray">，从聊天记录中生成个性化洞察。</Text>
      </Box>



      <ChatView
        messages = {messages}
        streamingText={streamingText}
      />

      <Box marginTop={1} paddingLeft={1}>
        <Text color="magenta bold">{'> '}</Text>
        <TextInput
          value={value}
          onChange={setValue}
          onSubmit={handleSubmit}
          placeholder="输入您的消息或 @ 文件路径"
        />
      </Box>

    </Box>
  );
}

import { Box, Text } from "ink";
import React from "react";

interface Props {
    messages: ChatMessage[];
    streamingText?: string;
}

export interface ChatMessage {
    role: "user" | "assistant";
    content: string;
}

export function ChatView({ messages, streamingText }: Props) {
    return (
        <Box flexDirection="column" paddingLeft={1}>
            {messages.map((msg, i) => (
                <MessageBlock key={i} message={msg} />
            ))}
            {streamingText !== undefined && streamingText !== "" && (
                <Box>
                    <Text>
                        {streamingText} --
                    </Text>
                </Box>
            )}
        </Box>
    );
}


function MessageBlock({ message }: { message: ChatMessage }) {
    switch (message.role) {
        case "user":
            return (
                <Box marginBottom={0}>
                    <Text color="red">
                        {message.content}
                    </Text>
                </Box>
            );

        case "assistant":
            return (
                <Box marginBottom={0}>
                    <Text>{message.content}</Text>
                </Box>
            );


        default:
            return null;
    }
}

