let fullText = "";
const toolCalls: string[] = [];

for await (const chunk of response) {
  const [messageChunk, metadata] = chunk as [any, any];
  const msgType = messageChunk?._getType?.() || messageChunk?.getType?.() || "";

  // AIMessageChunk → 文本内容
  if ((msgType === "ai" || msgType === "AIMessageChunk") && messageChunk.content) {
    fullText += messageChunk.content;
    setStreamingText(fullText);
  }

  // ToolMessage → 工具调用结果
  if (msgType === "tool" || msgType === "ToolMessage") {
    const toolName = metadata?.toolName || messageChunk.name || "unknown";
    const toolResult = typeof messageChunk.content === "string"
      ? messageChunk.content
      : JSON.stringify(messageChunk.content);
    toolCalls.push(`[工具: ${toolName}] ${toolResult}`);
  }

  // AIMessageChunk 中包含 tool_calls 字段
  if (messageChunk.tool_calls && messageChunk.tool_calls.length > 0) {
    for (const tc of messageChunk.tool_calls) {
      toolCalls.push(`[调用工具: ${tc.name}] ${JSON.stringify(tc.args)}`);
    }
  }
}

